import sys
from collections import defaultdict

def mex(a, b, c):
    s = {a, b, c}
    for i in range(4):
        if i not in s:
            return i

def main():
    import sys
    input = sys.stdin.read
    data = input().split()
    N = int(data[0])
    A = list(map(int, data[1:N+1]))
    S = data[N+1]

    # Precompute positions for M, E, X
    m_pos = []
    e_pos = []
    x_pos = []
    for i in range(N):
        if S[i] == 'M':
            m_pos.append(i)
        elif S[i] == 'E':
            e_pos.append(i)
        elif S[i] == 'X':
            x_pos.append(i)

    # Find all MEX triplets
    total = 0
    for m in m_pos:
        for e in e_pos:
            if e <= m:
                continue
            for x in x_pos:
                if x <= e:
                    continue
                # Check if i < j < k
                if m < e < x:
                    total += mex(A[m], A[e], A[x])

    print(total)

if __name__ == "__main__":
    main()
